/**
 * Database service for managing MySQL connections
 */
public class DatabaseService {

    /**
     * Establishes a database connection using provided parameters
     *
     * @param url      MySQL database connection URL
     * @param username Database username
     * @param password Database password
     * @return Established database connection
     * @throws SQLException if database connection fails
     */
    public Connection connectToDatabase(String url, String username, String password) throws SQLException {
        // Validate input parameters
        if (url == null || url.trim().isEmpty()) {
            throw new IllegalArgumentException("Database URL cannot be null or empty");
        }

        if (username == null) {
            throw new IllegalArgumentException("Username cannot be null");
        }

        // Ensure the URL is for MySQL
        if (!url.startsWith("jdbc:mysql://")) {
            throw new IllegalArgumentException("Only MySQL database URLs are supported (must start with jdbc:mysql://)");
        }

        try {
            // Load MySQL JDBC driver (optional for JDBC 4.0+, but good practice)
            Class.forName("com.mysql.cj.jdbc.Driver");
        } catch (ClassNotFoundException e) {
            // Fallback to older driver name for compatibility
            try {
                Class.forName("com.mysql.jdbc.Driver");
            } catch (ClassNotFoundException ex) {
                throw new SQLException("MySQL JDBC Driver not found. Please include MySQL connector in classpath.", ex);
            }
        }

        // Establish and return the connection
        return DriverManager.getConnection(url, username, password);
    }
}
